+                    <div class="channel-item @(channel.Id == activeChannelId ? "active" : "")"
+                         @onclick="() => SelectChannelAsync(channel)">
+                        <div class="channel-name"># @channel.Name</div>
+                        <div class="channel-description">@TruncateDescription(channel.Description)</div>
+                        @if (channel.UnreadCount > 0)
+                        {
+                            <span class="unread-badge">@channel.UnreadCount</span>
+                        }
+                    </div>
+                }
+            }
+        </div>
+    </div>
+
+    @* Main Message Area *@
+    <div class="chat-main @(threadRootMessage is null ? "full-width" : "")">
+        @if (activeChannel is not null)
+        {
+            <div class="main-header">
+                <h2># @activeChannel.Name</h2>
+                <p>@activeChannel.Description</p>
+            </div>
+
+            <div class="message-list" @ref="messageListRef" @onscroll="OnMessageListScrollAsync">
+                @if (isLoadingOlder)
+                {
+                    <div class="loading-indicator">Loading older messages...</div>
+                }
+                @if (messages is not null)
+                {
+                    @foreach (var message in messages)
+                    {
+                        <div class="message-item" @onmouseenter="() => hoveredMessageId = message.Id"
+                             @onmouseleave="() => hoveredMessageId = null">
+                            <div class="message-header">
+                                <span class="message-author">@message.Author</span>
+                                <span class="message-time">@FormatRelativeTime(message.SentAt)</span>
+                            </div>
+                            <div class="message-content">@message.Content</div>
+
+                            @if (message.Reactions.Count > 0)
+                            {
+                                <div class="reaction-list">
+                                    @foreach (var reaction in message.Reactions)
+                                    {
+                                        <span class="reaction-badge" title="@string.Join(", ", reaction.Users)"
+                                              @onclick="() => AddReactionAsync(message.Id, reaction.Emoji)">
+                                            @reaction.Emoji @reaction.Users.Count
+                                        </span>
+                                    }
+                                </div>
+                            }
+
+                            @if (threadSummaries.TryGetValue(message.Id, out var summary))
+                            {
+                                <div class="thread-link" @onclick="() => OpenThreadAsync(message)">
+                                    @summary.ReplyCount replies &middot; Last reply @FormatRelativeTime(summary.LastReplyAt)
+                                </div>
+                            }
+
+                            @if (hoveredMessageId == message.Id)
+                            {
+                                <div class="message-actions">
+                                    <button class="action-btn" @onclick="() => OpenThreadAsync(message)" title="Reply in thread">
+                                        💬 Reply
+                                    </button>
+                                    <button class="action-btn" @onclick="() => ToggleEmojiPicker(message.Id)" title="Add reaction">
+                                        😀 React
+                                    </button>
+                                </div>
+
+                                @if (emojiPickerMessageId == message.Id)
+                                {
+                                    <div class="emoji-picker">
+                                        @foreach (var emoji in commonEmojis)
+                                        {
+                                            <button class="emoji-btn" @onclick="() => AddReactionAsync(message.Id, emoji)">
+                                                @emoji
+                                            </button>
+                                        }
+                                    </div>
+                                }
+                            }
+                        </div>
+                    }
+                }
+            </div>
+
+            <div class="message-input-area">
+                <textarea @bind="newMessageContent" @bind:event="oninput"
+                          @onkeydown="OnMessageKeyDownAsync"
+                          placeholder="Type a message..." rows="2"></textarea>
+                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(newMessageContent)">
+                    Send
+                </button>
+            </div>
+        }
+        else
+        {
+            <div class="no-channel-selected">
+                <p>Select a channel to start chatting</p>
+            </div>
+        }
+    </div>
+
+    @* Right Panel - Thread View *@
+    @if (threadRootMessage is not null)
+    {
+        <div class="chat-thread-panel">
+            <div class="thread-header">
+                <h3>Thread</h3>
+                <button class="close-btn" @onclick="CloseThread">&times;</button>
+            </div>
+            <div class="thread-root-message">
+                <div class="message-header">
+                    <span class="message-author">@threadRootMessage.Author</span>
+                    <span class="message-time">@FormatRelativeTime(threadRootMessage.SentAt)</span>
+                </div>
+                <div class="message-content">@threadRootMessage.Content</div>
+            </div>
+            <div class="thread-replies">
+                @if (threadMessages is not null)
+                {
+                    @foreach (var reply in threadMessages)
+                    {
+                        <div class="message-item">
+                            <div class="message-header">
+                                <span class="message-author">@reply.Author</span>
+                                <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
+                            </div>
+                            <div class="message-content">@reply.Content</div>
+                            @if (reply.Reactions.Count > 0)
+                            {
+                                <div class="reaction-list">
+                                    @foreach (var reaction in reply.Reactions)
+                                    {
+                                        <span class="reaction-badge">@reaction.Emoji @reaction.Users.Count</span>
+                                    }
+                                </div>
+                            }
+                        </div>
+                    }
+                }
+            </div>
+            <div class="message-input-area">
+                <textarea @bind="threadReplyContent" @bind:event="oninput"
+                          @onkeydown="OnThreadKeyDownAsync"
+                          placeholder="Reply in thread..." rows="2"></textarea>
+                <button class="send-btn" @onclick="SendThreadReplyAsync" disabled="@string.IsNullOrWhiteSpace(threadReplyContent)">
+                    Reply
+                </button>
+            </div>
+        </div>
+    }
+</div>
+
+@code {
+    private List<Channel>? channels;
+    private List<Message>? messages;
+    private List<Message>? threadMessages;
+    private Dictionary<int, ThreadSummary> threadSummaries = new();
+
+    private Channel? activeChannel;
+    private int? activeChannelId;
+    private Message? threadRootMessage;
+
+    private string newMessageContent = "";
+    private string threadReplyContent = "";
+
+    private int? hoveredMessageId;
+    private int? emojiPickerMessageId;
+
+    private bool isLoadingOlder;
+    private bool hasMoreMessages = true;
+    private const int PageSize = 30;
+
+    private ElementReference messageListRef;
+    private DotNetObjectReference<Chat>? dotNetRef;
+
+    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];
+
+    protected override async Task OnInitializedAsync()
+    {
+        channels = await ChatService.GetChannelsAsync();
+        dotNetRef = DotNetObjectReference.Create(this);
+    }
+
+    private async Task SelectChannelAsync(Channel channel)
+    {
+        activeChannel = channel;
+        activeChannelId = channel.Id;
+        messages = null;
+        threadSummaries.Clear();
+        hasMoreMessages = true;
+        emojiPickerMessageId = null;
+
+        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
+        hasMoreMessages = messages.Count == PageSize;
+        await BuildThreadSummaries();
+        await ChatService.MarkChannelReadAsync(channel.Id);
+
+        // Refresh channel list to update unread counts
+        channels = await ChatService.GetChannelsAsync();
+    }
+
+    private async Task BuildThreadSummaries()
+    {
+        if (messages is null) return;
+
+        threadSummaries.Clear();
+        var messageIds = messages.Select(m => m.Id).ToHashSet();
+
+        foreach (var msg in messages)
+        {
+            if (msg.ReplyToId is not null && messageIds.Contains(msg.ReplyToId.Value))
+            {
+                if (!threadSummaries.ContainsKey(msg.ReplyToId.Value))
+                {
+                    threadSummaries[msg.ReplyToId.Value] = new ThreadSummary(msg.ReplyToId.Value, 0, msg.SentAt);
+                }
+
+                var existing = threadSummaries[msg.ReplyToId.Value];
+                threadSummaries[msg.ReplyToId.Value] = existing with
+                {
+                    ReplyCount = existing.ReplyCount + 1,
+                    LastReplyAt = msg.SentAt > existing.LastReplyAt ? msg.SentAt : existing.LastReplyAt
+                };
+            }
+        }
+    }
+
+    private async Task OnMessageListScrollAsync()
+    {
+        if (isLoadingOlder || !hasMoreMessages || messages is null || activeChannelId is null)
+            return;
+
+        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
+        if (scrollTop <= 0)
+        {
+            await LoadOlderMessagesAsync();
+        }
+    }
+
+    private async Task LoadOlderMessagesAsync()
+    {
+        if (isLoadingOlder || !hasMoreMessages || messages is null || activeChannelId is null) return;
+
+        isLoadingOlder = true;
+        StateHasChanged();
+
+        var olderMessages = await ChatService.GetMessagesAsync(activeChannelId.Value, messages.Count, PageSize);
+        hasMoreMessages = olderMessages.Count == PageSize;
+
+        if (olderMessages.Count > 0)
+        {
+            messages.InsertRange(0, olderMessages);
+            await BuildThreadSummaries();
+        }
+
+        isLoadingOlder = false;
+    }
+
+    private async Task SendMessageAsync()
+    {
+        if (string.IsNullOrWhiteSpace(newMessageContent) || activeChannelId is null) return;
+
+        var sent = await ChatService.SendMessageAsync(activeChannelId.Value, newMessageContent.Trim(), null);
+        newMessageContent = "";
+        messages?.Add(sent);
+
+        await ScrollToBottomAsync();
+    }
+
+    private async Task OnMessageKeyDownAsync(KeyboardEventArgs e)
+    {
+        if (e.Key == "Enter" && !e.ShiftKey)
+        {
+            await SendMessageAsync();
+        }
+    }
+
+    private async Task OnThreadKeyDownAsync(KeyboardEventArgs e)
+    {
+        if (e.Key == "Enter" && !e.ShiftKey)
+        {
+            await SendThreadReplyAsync();
+        }
+    }
+
+    private async Task OpenThreadAsync(Message message)
+    {
+        threadRootMessage = message;
+        emojiPickerMessageId = null;
+
+        var allThreadMessages = await ChatService.GetThreadAsync(message.Id);
+        threadMessages = allThreadMessages.Where(m => m.Id != message.Id).ToList();
+    }
+
+    private void CloseThread()
+    {
+        threadRootMessage = null;
+        threadMessages = null;
+        threadReplyContent = "";
+    }
+
+    private async Task SendThreadReplyAsync()
+    {
+        if (string.IsNullOrWhiteSpace(threadReplyContent) || threadRootMessage is null || activeChannelId is null) return;
+
+        var reply = await ChatService.SendMessageAsync(activeChannelId.Value, threadReplyContent.Trim(), threadRootMessage.Id);
+        threadReplyContent = "";
+        threadMessages?.Add(reply);
+        messages?.Add(reply);
+        await BuildThreadSummaries();
+    }
+
+    private async Task AddReactionAsync(int messageId, string emoji)
+    {
+        await ChatService.AddReactionAsync(messageId, emoji);
+        emojiPickerMessageId = null;
+
+        // Refresh messages to show updated reactions
+        if (activeChannelId is not null && messages is not null)
+        {
+            messages = await ChatService.GetMessagesAsync(activeChannelId.Value, 0, messages.Count);
+            await BuildThreadSummaries();
+        }
+
+        if (threadRootMessage is not null)
+        {
+            var allThreadMessages = await ChatService.GetThreadAsync(threadRootMessage.Id);
+            threadMessages = allThreadMessages.Where(m => m.Id != threadRootMessage.Id).ToList();
+        }
+    }
+
+    private void ToggleEmojiPicker(int messageId)
+    {
+        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
+    }
+
+    private async Task ScrollToBottomAsync()
+    {
+        await JS.InvokeVoidAsync("eval", "setTimeout(() => { const el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight; }, 50)");
+    }
+
+    private static string FormatRelativeTime(DateTime sentAt)
+    {
+        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
+
+        if (diff.TotalSeconds < 60) return "just now";
+        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
+        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
+        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
+        return sentAt.ToString("MMM d, yyyy");
+    }
+
+    private static string TruncateDescription(string description)
+    {
+        return description.Length > 40 ? description[..37] + "..." : description;
+    }
+
+    public ValueTask DisposeAsync()
+    {
+        dotNetRef?.Dispose();
+        return ValueTask.CompletedTask;
+    }
+}
+

